        const currentRoundNumber = res.data.currentRound;
        const rounds = res.data.rounds || [];
        const roundObj = rounds[currentRoundNumber - 1];
        const roundId = roundObj?._id;

        // Now you can use the refs here (they're declared at component level)
        const roundNumberChanged = currentRoundNumber !== lastRoundNumberRef.current;
        const roundIdChanged = roundId && lastRoundIdRef.current !== roundId;

        if (roundNumberChanged || roundIdChanged) {
          console.log('🚀 Round change detected:', {
            numberChanged: roundNumberChanged,
            idChanged: roundIdChanged,
            oldNumber: lastRoundNumberRef.current,
            newNumber: currentRoundNumber,
            oldId: lastRoundIdRef.current,
            newId: roundId
          });

          // Update refs
          lastRoundNumberRef.current = currentRoundNumber;
          lastRoundIdRef.current = roundId;

          // Send data immediately
          const nextRoundIndex = currentRoundNumber;
