          setLastPlayerData(mapPlayerDataForCaptivate(res.data, roundObj));
          roundObj._sentToCaptivate = true; // Prevent duplicate sends in polling
        }
      } catch (err) {
        console.error('Error polling game state:', err);
      }
    };

    fetchGameState();
